import{_ as e,o as t,c as s,a3 as n}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"53. Payment Of Wages","description":"","frontmatter":{"title":"53. Payment Of Wages","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["wages","preliminary"]},"headers":[],"relativePath":"ebas/mspp/classification-salaries/53-payment-of-wages.md","filePath":"ebas/mspp/classification-salaries/53-payment-of-wages.md"}'),o={name:"ebas/mspp/classification-salaries/53-payment-of-wages.md"};function i(r,a,p,l,m,c){return t(),s("div",null,[...a[0]||(a[0]=[n('<h1 id="_53-payment-of-wages" tabindex="-1">53. Payment Of Wages <a class="header-anchor" href="#_53-payment-of-wages" aria-label="Permalink to &quot;53. Payment Of Wages&quot;">​</a></h1><p><strong>a.</strong> Subject to any individual arrangements between an Employer and an Employee wages shall be paid no later than a Thursday.</p><p><strong>b.</strong> On or prior to the pay day the Employer shall state to each Employee in writing the amount of wages to which they are entitled, the amount of deductions there from, and the net amount being paid to them.</p><p><strong>c.</strong> Additional provisions apply at the Royal Children’s Hospital and the Royal Women’s Hospital. See <a href="/eba/ebas/mspp/schedules/8-royal-women-s-hospital-royal-children-s-hospital-general-emp.html">Schedule 8</a> .</p><p>Plain language terms: pay day, pay cycle, payslip.</p>',5)])])}const y=e(o,[["render",i]]);export{h as __pageData,y as default};
